//! Statistical inference tools for computing standard errors and hypothesis tests
//!
//! This crate provides centralized tools for statistical inference, including
//! standard errors, p-values, confidence intervals, and robust covariance
//! estimators (e.g., sandwich estimators HC0-HC3).

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use ndarray::Array2;

/// Statistical inference errors
#[derive(thiserror::Error, Debug)]
pub enum InferenceError {
    /// Matrix computation error
    #[error("Matrix computation error: {0}")]
    Matrix(String),
    /// Invalid degrees of freedom
    #[error("Invalid degrees of freedom: {0}")]
    DegreesOfFreedom(i32),
}

/// Compute standard errors from variance-covariance matrix
pub fn standard_errors(vcov: &Array2<f64>) -> Vec<f64> {
    let mut se = Vec::new();
    for i in 0..vcov.nrows() {
        se.push(vcov[[i, i]].sqrt());
    }
    se
}

/// Compute t-statistics given coefficients and standard errors  
pub fn t_statistics(coefficients: &[f64], std_errors: &[f64]) -> Vec<f64> {
    coefficients
        .iter()
        .zip(std_errors.iter())
        .map(|(coef, se)| coef / se)
        .collect()
}

/// Compute two-tailed p-values from t-statistics
pub fn t_test_p_values(t_stats: &[f64], df: i32) -> Vec<f64> {
    t_stats
        .iter()
        .map(|&t| {
            // Two-tailed p-value: P(|T| > |t|) = 2 * P(T > |t|)
            let abs_t = t.abs();
            2.0 * (1.0 - t_cdf(abs_t, df))
        })
        .collect()
}

/// Cumulative distribution function for Student's t-distribution
/// Uses the relationship: t_cdf(t, df) = 1/2 + t * gamma((df+1)/2) / (sqrt(pi*df) * gamma(df/2)) * F(1/2, (df+1)/2; 3/2; -t²/df)
/// Where F is the hypergeometric function. For practical purposes, we use the beta distribution relationship.
fn t_cdf(t: f64, df: i32) -> f64 {
    if df <= 0 {
        return 0.5; // Invalid df, return neutral p-value
    }

    if t.is_infinite() {
        return if t > 0.0 { 1.0 } else { 0.0 };
    }

    // For large df (>= 30), approximate with standard normal
    if df >= 30 {
        return standard_normal_cdf(t);
    }

    // Use the relationship between t-distribution and beta distribution
    // If T ~ t(df), then (T² / (T² + df)) ~ Beta(1/2, df/2)
    let df_f = df as f64;
    let x = t * t / (t * t + df_f);

    if t >= 0.0 {
        0.5 + 0.5 * incomplete_beta(0.5, df_f / 2.0, x)
    } else {
        0.5 - 0.5 * incomplete_beta(0.5, df_f / 2.0, x)
    }
}

/// Standard normal CDF approximation using rational approximation
fn standard_normal_cdf(x: f64) -> f64 {
    // Abramowitz and Stegun approximation 7.1.26
    let a1 = 0.254829592;
    let a2 = -0.284496736;
    let a3 = 1.421413741;
    let a4 = -1.453152027;
    let a5 = 1.061405429;
    let p = 0.3275911;

    let sign = if x < 0.0 { -1.0 } else { 1.0 };
    let x = x.abs() / 2.0_f64.sqrt();

    let t = 1.0 / (1.0 + p * x);
    let y = 1.0 - (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t * (-x * x).exp();

    0.5 * (1.0 + sign * y)
}

/// Incomplete beta function approximation
/// This is a simplified implementation - a full implementation would use continued fractions
fn incomplete_beta(a: f64, b: f64, x: f64) -> f64 {
    if x <= 0.0 {
        return 0.0;
    }
    if x >= 1.0 {
        return 1.0;
    }

    // For small parameters, use a simple series approximation
    // This is not highly accurate but sufficient for basic statistical inference
    let mut result = 0.0;
    let mut term = x.powf(a) * (1.0 - x).powf(b) / (a * beta_function(a, b));

    for n in 0..50 {
        result += term;
        term *= x * (a + n as f64) / ((a + b + n as f64) * (n as f64 + 1.0));
        if term.abs() < 1e-10 {
            break;
        }
    }

    result.min(1.0)
}

/// Beta function B(a, b) = Γ(a)Γ(b)/Γ(a+b)
/// Approximation using logarithmic gamma function
fn beta_function(a: f64, b: f64) -> f64 {
    (log_gamma(a) + log_gamma(b) - log_gamma(a + b)).exp()
}

/// Logarithmic gamma function approximation using Stirling's formula
fn log_gamma(x: f64) -> f64 {
    if x < 1.0 {
        return log_gamma(x + 1.0) - x.ln();
    }

    // Stirling's approximation: ln(Γ(x)) ≈ (x - 0.5) * ln(x) - x + 0.5 * ln(2π)
    (x - 0.5) * x.ln() - x + 0.5 * (2.0 * std::f64::consts::PI).ln()
}

/// Compute F-statistic p-value using F-distribution
///
/// For F(f; df1, df2) = P(F ≤ f), where F follows F-distribution with df1, df2 degrees of freedom
pub fn f_test_p_value(f_stat: f64, df1: i32, df2: i32) -> f64 {
    if f_stat <= 0.0 || df1 <= 0 || df2 <= 0 {
        return 1.0;
    }

    // F distribution p-value: P(F > f_stat) = 1 - I_x(df1/2, df2/2)
    // where x = df1*f_stat / (df1*f_stat + df2) and I is regularized incomplete beta function
    let x = (df1 as f64 * f_stat) / (df1 as f64 * f_stat + df2 as f64);
    let a = df1 as f64 / 2.0;
    let b = df2 as f64 / 2.0;

    1.0 - incomplete_beta(a, b, x)
}

/// Calculate overall F-statistic for model significance
/// Tests null hypothesis that all non-intercept coefficients are zero
pub fn model_f_statistic(rss_full: f64, rss_null: f64, df_model: usize, df_resid: usize) -> f64 {
    if df_model == 0 || df_resid == 0 || rss_full <= 0.0 {
        return 0.0;
    }

    let explained_ss = rss_null - rss_full;
    let mse_model = explained_ss / df_model as f64;
    let mse_resid = rss_full / df_resid as f64;

    if mse_resid <= 0.0 {
        return f64::INFINITY;
    }

    mse_model / mse_resid
}

