//! Exponential family distributions for generalized linear models
//!
//! This crate provides family structs that specify variance functions and
//! default link functions for GLM fitting.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use link::{Identity, LinkFn, Log, Logit};

/// Trait for exponential family distributions
pub trait Family {
    /// Associated link function type
    type Link: LinkFn;

    /// Variance function V(μ)
    fn variance(&self, mu: f64) -> f64;

    /// Default link function
    fn link(&self) -> Self::Link;

    /// Deviance residual
    fn dev_resid(&self, y: f64, mu: f64) -> f64;
}

/// Gaussian (normal) family
#[derive(Debug, Default)]
pub struct Gaussian;

impl Family for Gaussian {
    type Link = Identity;

    fn variance(&self, _mu: f64) -> f64 {
        1.0
    }

    fn link(&self) -> Self::Link {
        Identity
    }

    fn dev_resid(&self, y: f64, mu: f64) -> f64 {
        (y - mu).powi(2)
    }
}

/// Poisson family
#[derive(Debug, Default)]
pub struct Poisson;

impl Family for Poisson {
    type Link = Log;

    fn variance(&self, mu: f64) -> f64 {
        mu
    }

    fn link(&self) -> Self::Link {
        Log
    }

    fn dev_resid(&self, y: f64, mu: f64) -> f64 {
        if y == 0.0 {
            2.0 * mu
        } else {
            2.0 * (y * (y / mu).ln() - (y - mu))
        }
    }
}

/// Binomial family
#[derive(Debug, Default)]
pub struct Binomial;

impl Family for Binomial {
    type Link = Logit;

    fn variance(&self, mu: f64) -> f64 {
        mu * (1.0 - mu)
    }

    fn link(&self) -> Self::Link {
        Logit
    }

    fn dev_resid(&self, y: f64, mu: f64) -> f64 {
        let y_log_term = if y > 0.0 { y * (y / mu).ln() } else { 0.0 };
        let one_minus_y_log_term = if y < 1.0 {
            (1.0 - y) * ((1.0 - y) / (1.0 - mu)).ln()
        } else {
            0.0
        };
        2.0 * (y_log_term + one_minus_y_log_term)
    }
}

